import java.util.stream.Stream;
import org.jetbrains.mps.openapi.model.SNode;
import jetbrains.mps.lang.smodel.generator.smodelAdapter.SNodeOperations;
import org.jetbrains.mps.openapi.module.SRepository;
import jetbrains.mps.smodel.ModelDependencyResolver;
import jetbrains.mps.smodel.language.LanguageRegistry;

/**
 * Utility to retrieve platform for model and modules.
 */
public class PlatformHelper {
  private static TargetPlatform defaultPlatform = TargetPlatform.getMpsDefault();

  @NotNull
  private static Optional<TargetPlatform> getStubPlatform(SModelReference model) {
    final String stereotype = model.getName().getStereotype();
    return KotlinModelKind.getSupported().stream().filter((it) -> Objects.equals(it.getStereotype(), stereotype)).findFirst().map((it) -> it.getPlatform());
  }

  public static TargetPlatform getModelDefaultPlatform(SModel model) {
    return getStubPlatform(SModelOperations.getPointer(model)).orElse(defaultPlatform);
  }

  /**
   * Returns true if the given model may contain declarations for the given platform.
   * 
   * This is useful to filter out certain stubs models that are known to contain only a specific set of platforms.
   */
  public static boolean canProvide(SModel model, @NotNull final TargetPlatform queriedPlatform) {
    return getStubPlatform(SModelOperations.getPointer(model)).map((explicitPlatform) -> explicitPlatform.containsAll(queriedPlatform)).orElse(true);
  }

  public static Stream<SModel> compatibleImportedModels(SNode contextNode, @NotNull final TargetPlatform platform) {
    SModel model = SNodeOperations.getModel(contextNode);
    SRepository repository = model.getRepository();

    Stream<SModel> imports;
    if (repository == null) {
      // hack for scenarios when one needs scope for a dynamic reference during generation (transient models are not in a repo),
      // we use deprecated method kept for the very same reason
      imports = jetbrains.mps.smodel.SModelOperations.allImportedModels(model).stream();
    } else {
      ModelDependencyResolver resolver = new ModelDependencyResolver(LanguageRegistry.getInstance(repository), repository);
      imports = Stream.concat(resolver.directImports(model).stream(), resolver.implicitImports(model).stream());
    }


    return Stream.concat(Stream.of(model), imports).distinct().filter((m) -> canProvide(m, platform));
  }
}
